import 'package:flutter/material.dart';
import 'book_detail_page.dart'; // Detay sayfasını import ediyoruz

class HomePage extends StatefulWidget {
  const HomePage({Key? key}) : super(key: key);

  @override
  State<HomePage> createState() => _HomePageState();
}

class _HomePageState extends State<HomePage> {
  // Veritabanından (API) gelecek örnek dinamik kitap verisi listesi
  final List<Map<String, dynamic>> _books = [
    {
      'id': 1,
      'baslik': 'Nutuk',
      'yazar': 'Mustafa Kemal Atatürk',
      'fiyat': 120.0,
      'kiralikFiyat': 15.0,
      'stok': 12,
      'isbn': '9789751601339',
      'kategori': 'Tarih',
      'resim': 'data:image/jpeg;base64,',
      'acıklama': 'Türkiye Cumhuriyeti\'nin kuruluş belgesi niteliğindeki tarihi nutuk.'
    },
    {
      'id': 2,
      'baslik': 'Suç ve Ceza',
      'yazar': 'Fyodor Dostoyevski',
      'fiyat': 85.50,
      'kiralikFiyat': 10.0,
      'stok': 5,
      'isbn': '9789750719370',
      'kategori': 'Klasik',
      'resim': 'data:image/jpeg;base64,',
      'acıklama': 'Raskolnikov adlı gencin vicdanı ve işlediği cinayet arasındaki psikolojik savaşı.'
    },
    {
      'id': 3,
      'baslik': 'Sapiens',
      'yazar': 'Yuval Noah Harari',
      'fiyat': 145.0,
      'kiralikFiyat': 20.0,
      'stok': 8,
      'isbn': '9786054729111',
      'kategori': 'Bilim',
      'resim': 'data:image/jpeg;base64,',
      'acıklama': 'İnsan türünün kısa bir tarihi.'
    }
  ];

  // Örnek Kategoriler (Şemandaki KATEGORI tablosu için)
  final List<String> _categories = ['Tümü', 'Tarih', 'Klasik', 'Bilim', 'Roman', 'Felsefe'];

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: Colors.grey[100],
      // --- APPBAR: Arama Seçenekleri İçeriyor ---
      appBar: AppBar(
        title: const Text('Dijital Kütüphane', style: TextStyle(fontWeight: FontWeight.bold)),
        backgroundColor: Colors.deepPurple,
        foregroundColor: Colors.white,
        actions: [
          IconButton(
            icon: const Icon(Icons.search_rounded),
            onPressed: () {
              // Arama butonuna basıldığında yapılacak işlemler (SearchDelegate vb.)
              ScaffoldMessenger.of(context).showSnackBar(
                const SnackBar(content: Text('Arama sayfası açılıyor...')),
              );
            },
          ),
          IconButton(
            icon: const Icon(Icons.filter_list_rounded),
            onPressed: () {
              // Gelişmiş filtreleme seçenekleri
            },
          ),
        ],
      ),
      body: SingleChildScrollView(
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            // 1. Bölüm: Kategoriler/Türler (Yatay Liste)
            const Padding(
              padding: EdgeInsets.only(left: 16.0, top: 16.0, bottom: 8.0),
              child: Text(
                "Kitap Türleri",
                style: TextStyle(fontSize: 20, fontWeight: FontWeight.bold, color: Colors.deepPurple),
              ),
            ),
            SizedBox(
              height: 50,
              child: ListView.builder(
                scrollDirection: Axis.horizontal,
                padding: const EdgeInsets.symmetric(horizontal: 12),
                itemCount: _categories.length,
                itemBuilder: (context, index) {
                  return Card(
                    color: index == 0 ? Colors.deepPurple : Colors.white,
                    shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(20)),
                    child: Padding(
                      padding: const EdgeInsets.symmetric(horizontal: 20, vertical: 8),
                      child: Center(
                        child: Text(
                          _categories[index],
                          style: TextStyle(
                            color: index == 0 ? Colors.white : Colors.black87,
                            fontWeight: FontWeight.bold,
                          ),
                        ),
                      ),
                    ),
                  );
                },
              ),
            ),

            // 2. Bölüm: Popüler Sıralamaya Göre Kitaplar (Dikey Liste)
            const Padding(
              padding: EdgeInsets.only(left: 16.0, top: 24.0, bottom: 8.0),
              child: Text(
                "Popüler Kitaplar",
                style: TextStyle(fontSize: 20, fontWeight: FontWeight.bold, color: Colors.deepPurple),
              ),
            ),

            // Dinamik Kitap Listesi
            ListView.builder(
              shrinkWrap: true, // SingleChildScrollView içinde düzgün çalışması için
              physics: const NeverScrollableScrollPhysics(),
              padding: const EdgeInsets.symmetric(horizontal: 16),
              itemCount: _books.length,
              itemBuilder: (context, index) {
                final book = _books[index];

                // --- KİTAP KARTI ---
                return GestureDetector(
                  // DİNAMİK GEÇİŞ: Tıklanan kitabın tüm map verisini detay sayfasına gönderiyoruz
                  onTap: () {
                    Navigator.push(
                      context,
                      MaterialPageRoute(
                        builder: (context) => BookDetailPage(bookData: book),
                      ),
                    );
                  },
                  child: Card(
                    margin: const EdgeInsets.all(6.0),
                    shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(15)),
                    elevation: 2,
                    child: Padding(
                      padding: const EdgeInsets.all(12.0),
                      child: Row(
                        children: [
                          // Kitap Resmi
                          ClipRRect(
                            borderRadius: BorderRadius.circular(10),
                            child: Image.network(
                              book['resim'],
                              width: 80,
                              height: 110,
                              fit: BoxFit.cover,
                            ),
                          ),
                          const SizedBox(width: 16),
                          // Kitap Bilgileri
                          Expanded(
                            child: Column(
                              crossAxisAlignment: CrossAxisAlignment.start,
                              children: [
                                Text(
                                  book['baslik'],
                                  style: const TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
                                  maxLines: 1,
                                  overflow: TextOverflow.ellipsis,
                                ),
                                const SizedBox(height: 4),
                                Text(
                                  book['yazar'],
                                  style: TextStyle(fontSize: 14, color: Colors.grey[600]),
                                ),
                                const SizedBox(height: 8),
                                Text(
                                  "${book['fiyat']} TL",
                                  style: const TextStyle(fontSize: 16, fontWeight: FontWeight.w600, color: Colors.deepPurple),
                                ),
                              ],
                            ),
                          ),
                          // İkon Seçenekleri (Favori ve Sepet)
                          Column(
                            children: [
                              IconButton(
                                icon: const Icon(Icons.favorite_border_rounded, color: Colors.red),
                                onPressed: () {
                                  // Favorilere ekleme lojistiği
                                },
                              ),
                              IconButton(
                                icon: const Icon(Icons.add_shopping_cart_rounded, color: Colors.deepPurple),
                                onPressed: () {
                                  // Şemandaki SEPET tablosuna (ekle) tetiklenecek yer
                                  ScaffoldMessenger.of(context).showSnackBar(
                                    SnackBar(content: Text('${book['baslik']} sepete eklendi!')),
                                  );
                                },
                              ),
                            ],
                          )
                        ],
                      ),
                    ),
                  ),
                );
              },
            ),
          ],
        ),
      ),
    );
  }
}